import { useEffect, useState } from 'react';
import './App.css';
// Importamos con Mayúscula
import CredencialesUsuario from './componentes/credenciales';
import { Routes } from 'react-router-dom';




function App() {
  const [data, setData] = useState([]);

  useEffect(() => {
    fetch('http://localhost:8081/usuarios')
      .then(res => res.json())
      .then(data => setData(data))
      .catch(err => console.log(err));
  }, []);

  return (
    <div className="App">
      <div className="ventana-de-registro">
          {/* Usamos la etiqueta con Mayúscula */}
        <div className="lado-derecho-registro">
          <CredencialesUsuario />  
        </div>
        <div className="lado-izquierdo-registro">
          <p className='estilo-de-texto-de-formulario-registro'>¡Bienvenidos!</p>
          <p className='estilo-de-texto-de-formulario-registro'>Nos alegra muchísimo que estés aquí. Este es un espacio pensado para ti, donde podrás aprender, compartir y crecer a tu propio ritmo.</p>
          <p className='estilo-de-texto-de-formulario-registro'>Queremos que te sientas cómodo/a desde el primer momento. Registrarte es el primer paso para formar parte de algo increíble. ¡Estamos emocionados de que quieras unirte!</p>
          <p className='estilo-de-texto-de-formulario-registro'>Completa el formulario y comienza esta nueva experiencia.</p>
          <p className='estilo-de-texto-de-formulario-registro'>¡Te esperamos!</p>
        </div>
      </div>
    </div>
  );
}

export default App;
